import type { Metadata } from "next";
import OperativeRecord from "./OperativeRecord";

export const metadata: Metadata = {
  title: "手術記録 / 麻酔記録 | ぐんじょう 電子カルテ",
  description:
    "手術室（手術部）で手術チームが術中・術後に使用する手術記録／麻酔記録画面。患者・術式・執刀医・麻酔科医・看護師・入退室時刻の手術ヘッダの上で、WHO手術安全チェックリスト（サインイン／タイムアウト／サインアウト）を運用する。タイムアウトは執刀前に執刀医と看護師の2人確認（co-sign）を必須とし、器械・ガーゼ・針の開始時／最終カウントを2人カウントで照合する。最終カウントが開始時と一致しない場合は体内遺残（retained foreign object）のリスクとして blocking アラートを発し、再カウント／X線確認を経るまでサインアウトをブロックする。麻薬・輸血の各実施は2人目の確認者による co-sign を必須とし、術中バイタル・麻酔薬・輸液／出血量の麻酔記録を時系列で記録する。手術記録（所見・手技・経過）は署名により確定し、確定後は追記（addendum）のみ可能な記録となる。",
};

export default function SurgeryPage() {
  return <OperativeRecord />;
}

"use client";

// ── Hand-rolled two-person verification (2人確認 / co-sign) ─────────────────────
// @gunjo/ui ships NO CoSign/DoubleCheck primitive. This screen needs the exact same
// "second actor signs, must differ from primary, with attestations" pattern FOUR
// times (time-out, counts, narcotics, transfusion), so it is built once here and
// reused. See FINDINGS-58 — this is the 3rd screen (#53, #56, now #58) that has had
// to re-implement this. The ideal would be a shipped <CoSign> component.

import * as React from "react";
import {
  IconCircleCheck,
  IconUserCheck,
  IconAlertTriangle,
} from "@tabler/icons-react";
import {
  Badge,
  Button,
  Checkbox,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  Textarea,
  FormField,
  FormLabel,
  FormControl,
  Input,
} from "@gunjo/ui";

export interface CoSignValue {
  signerId: string;
  reason?: string;
  attestedAt: string;
  attestations: string[];
}

export interface Attestation {
  id: string;
  label: React.ReactNode;
}

/* ── the "2人確認 済/要" pill (text + icon, never colour alone) ────────────── */

export function CoSignBadge({ value }: { value?: CoSignValue }) {
  return value ? (
    <Badge variant="success" className="gap-1">
      <IconCircleCheck className="h-3 w-3" aria-hidden />
      2人確認 済
    </Badge>
  ) : (
    <Badge variant="warning" className="gap-1">
      <IconAlertTriangle className="h-3 w-3" aria-hidden />
      2人確認 要
    </Badge>
  );
}

/* ── the composer dialog (controlled by `open`) ───────────────────────────── */

export function CoSignDialog({
  open,
  onOpenChange,
  title,
  description,
  primaryId,
  primaryRoleLabel = "1人目",
  signerLabel = "2人目 確認者（ID・氏名）",
  signerPlaceholder = "例：鈴木 花子 看護師",
  attestations,
  requireReason = false,
  reasonLabel = "確認・理由（任意）",
  reasonPlaceholder,
  confirmLabel = "2人確認を確定",
  onConfirm,
}: {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  title: React.ReactNode;
  description: React.ReactNode;
  primaryId: string;
  primaryRoleLabel?: string;
  signerLabel?: React.ReactNode;
  signerPlaceholder?: string;
  attestations: Attestation[];
  requireReason?: boolean;
  reasonLabel?: React.ReactNode;
  reasonPlaceholder?: string;
  confirmLabel?: React.ReactNode;
  onConfirm: (value: CoSignValue) => void;
}) {
  const [signerId, setSignerId] = React.useState("");
  const [reason, setReason] = React.useState("");
  const [ticked, setTicked] = React.useState<Set<string>>(new Set());

  // reset each time the dialog opens
  React.useEffect(() => {
    if (open) {
      setSignerId("");
      setReason("");
      setTicked(new Set());
    }
  }, [open]);

  const sameAsPrimary =
    signerId.trim().length > 0 && signerId.trim() === primaryId.trim();
  const allAttested = attestations.every((a) => ticked.has(a.id));
  const reasonOk = !requireReason || reason.trim().length >= 3;
  const canConfirm =
    signerId.trim().length >= 2 && allAttested && reasonOk && !sameAsPrimary;

  const toggle = (id: string) =>
    setTicked((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });

  const errId = "cosign-signer-err";

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>{title}</DialogTitle>
          <DialogDescription>{description}</DialogDescription>
        </DialogHeader>

        <div className="space-y-4">
          <div className="rounded-md border border-border bg-muted/30 px-3 py-2 text-xs text-muted-foreground">
            {primaryRoleLabel}：<span className="font-medium text-foreground">{primaryId}</span>
            <span className="ml-1">／ 2人目は別の担当者が独立に確認します。</span>
          </div>

          <FormField error={sameAsPrimary ? "同一人物では2人確認になりません。" : undefined}>
            <FormLabel>{signerLabel}</FormLabel>
            <FormControl>
              <Input
                value={signerId}
                onChange={(e) => setSignerId(e.target.value)}
                placeholder={signerPlaceholder}
                aria-describedby={sameAsPrimary ? errId : undefined}
              />
            </FormControl>
            {sameAsPrimary ? (
              <p id={errId} role="alert" className="text-xs font-medium text-destructive">
                <IconAlertTriangle className="mr-1 inline h-3 w-3" aria-hidden />
                1人目（{primaryId}）と同一です。別の担当者を指定してください。
              </p>
            ) : null}
          </FormField>

          <fieldset className="space-y-2">
            <legend className="mb-1 text-sm font-medium text-foreground">
              確認事項（2人目が独立に確認）
            </legend>
            {attestations.map((a) => (
              <Checkbox
                key={a.id}
                checked={ticked.has(a.id)}
                onCheckedChange={() => toggle(a.id)}
                label={a.label}
              />
            ))}
          </fieldset>

          {requireReason || reasonPlaceholder ? (
            <FormField>
              <FormLabel>{reasonLabel}</FormLabel>
              <FormControl>
                <Textarea
                  value={reason}
                  onChange={(e) => setReason(e.target.value)}
                  rows={2}
                  placeholder={reasonPlaceholder}
                />
              </FormControl>
            </FormField>
          ) : null}
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)}>
            キャンセル
          </Button>
          <Button
            variant="success"
            disabled={!canConfirm}
            onClick={() =>
              onConfirm({
                signerId: signerId.trim(),
                reason: reason.trim() || undefined,
                attestedAt: new Date().toISOString(),
                attestations: Array.from(ticked),
              })
            }
          >
            <IconUserCheck className="h-4 w-4" aria-hidden />
            {confirmLabel}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

/* ── compact audit line shown once signed ─────────────────────────────────── */

export function CoSignAudit({
  primaryId,
  value,
}: {
  primaryId: string;
  value: CoSignValue;
}) {
  const t = new Date(value.attestedAt);
  const hm = `${String(t.getHours()).padStart(2, "0")}:${String(
    t.getMinutes(),
  ).padStart(2, "0")}`;
  return (
    <p className="text-xs text-success-strong">
      <IconCircleCheck className="mr-1 inline h-3.5 w-3.5" aria-hidden />
      2人確認済 — 1人目 {primaryId} ／ 2人目 {value.signerId}（{hm}）
    </p>
  );
}

