}

function statusBadge(status: SurgeryStatus) {
  if (status === "準備")
    return (
      <Badge variant="secondary" className="gap-1">
        <IconClockHour4 className="h-3 w-3" aria-hidden />
        準備
      </Badge>
    );
  if (status === "手術中")
    return (
      <Badge variant="info" className="gap-1">
        <IconSlice className="h-3 w-3" aria-hidden />
        手術中
      </Badge>
    );
  return (
    <Badge variant="success" className="gap-1">
      <IconCircleCheck className="h-3 w-3" aria-hidden />
      退室済
    </Badge>
  );
}

/* intraop reference ranges for the anesthesia vitals */
const VITAL_RANGES = {
  hr: { low: 50, high: 100, criticalLow: 40, criticalHigh: 120 },
  map: { low: 65, high: 100, criticalLow: 55, criticalHigh: 120 },
  spo2: { low: 95, criticalLow: 90 },
  etco2: { low: 30, high: 45, criticalLow: 25, criticalHigh: 55 },
} as const;

/* ═══════════════════════════════════════════════════════════════════
   PAGE ROOT
   ═══════════════════════════════════════════════════════════════════ */

export default function OperativeRecord() {
  /* ── checklist state ── */
  const [checked, setChecked] = React.useState<Set<string>>(new Set());
  const toggleCheck = (id: string) =>
    setChecked((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });

  /* ── time-out two-person sign-off (co-sign #1) ── */
  const [timeoutCoSign, setTimeoutCoSign] = React.useState<CoSignValue | undefined>();
  const [timeoutDialog, setTimeoutDialog] = React.useState(false);

  /* ── counts (2人カウント) ── */
  const [counts, setCounts] = React.useState<CountRow[]>(initialCounts);
  const [countCoSign, setCountCoSign] = React.useState<CoSignValue | undefined>();
  const [countDialog, setCountDialog] = React.useState(false);
  // resolution of a mismatch: how the retained-object risk was cleared
  const [mismatchAck, setMismatchAck] = React.useState(false);
  const [resolution, setResolution] = React.useState("");

  /* ── narcotics / transfusion co-signs (#3, #4), keyed by admin id ── */
  const [controlled] = React.useState<ControlledAdmin[]>(initialControlled);
  const [adminCoSigns, setAdminCoSigns] = React.useState<Record<string, CoSignValue>>({});
  const [adminDialogFor, setAdminDialogFor] = React.useState<ControlledAdmin | null>(null);

  /* ── operative note (signed → append-only) ── */
  const [noteBody, setNoteBody] = React.useState(
    "全身麻酔下に仰臥位。臍部より気腹後、ポート4本留置。S状結腸を授動し、腸間膜を処理。病変部を含めS状結腸を切除、機能的端々吻合を施行。出血少量、術中合併症なし。",
  );
  const [noteSigned, setNoteSigned] = React.useState(false);
  const [noteSignedBy, setNoteSignedBy] = React.useState<string | null>(null);
  const [noteSignedAt, setNoteSignedAt] = React.useState<string | null>(null);
  const [addenda, setAddenda] = React.useState<
    { id: string; body: string; author: string; at: string }[]
  >([]);

  /* ── derived gates ─────────────────────────────────────────────── */

  const timeoutItems = checklistItems.filter((i) => i.phase === "timeout");
  const timeoutItemsDone = timeoutItems.every((i) => checked.has(i.id));
  const timeoutComplete = timeoutItemsDone && Boolean(timeoutCoSign);

  const countsWithEval = counts.map((row) => {
    const expected = expectedFinal(row);
    const counted = row.final !== null;
    const matches = counted && row.final === expected;
    return { row, expected, counted, matches };
  });
  const allCounted = countsWithEval.every((c) => c.counted);
  const mismatches = countsWithEval.filter((c) => c.counted && !c.matches);
  const hasMismatch = mismatches.length > 0;
  const countsReconciled =
    allCounted && Boolean(countCoSign) && (!hasMismatch || mismatchAck);

  const adminPending = controlled.filter((a) => !adminCoSigns[a.id]);
  const allAdminCoSigned = adminPending.length === 0;

  // サインアウト gating
  const signoutBlocked =
    !timeoutComplete || !countsReconciled || !allAdminCoSigned;
  const [signedOut, setSignedOut] = React.useState(false);

  const status: SurgeryStatus = signedOut
    ? "退室"
    : timeoutComplete
      ? "手術中"
      : "準備";

  /* ── stepper phase model ── */
  const steps: StepperStep[] = [
    {
      label: "サインイン",
      state: checklistItems
        .filter((i) => i.phase === "signin")
        .every((i) => checked.has(i.id))
        ? "completed"
        : "current",
    },
    {
      label: "タイムアウト",
      state: timeoutComplete
        ? "completed"
        : checklistItems.filter((i) => i.phase === "signin").every((i) => checked.has(i.id))
          ? "current"
          : "upcoming",
    },
    {
      label: "サインアウト",
      state: signedOut ? "completed" : timeoutComplete ? "current" : "upcoming",
    },
  ];

  /* ── count handlers ── */
  const setFinal = (id: string, value: number | null) => {
    setCounts((prev) => prev.map((r) => (r.id === id ? { ...r, final: value } : r)));
    // changing a count re-opens the mismatch question
    setMismatchAck(false);
    setCountCoSign(undefined);
  };

  /* ── narcotic/transfusion attestations ── */
  const adminAttestations = (a: ControlledAdmin): Attestation[] =>
    a.category === "麻薬"
      ? [
          { id: "drug", label: "薬剤名・規格が指示と一致することを確認した" },
          { id: "dose", label: "用量・投与経路が適切であることを確認した" },
          { id: "ledger", label: "麻薬施用簿への記載・残量を確認した" },
        ]
      : [
          { id: "patient", label: "患者・血液型・製造番号が照合表と一致することを確認した" },
          { id: "product", label: "製剤の外観・有効期限・交差適合試験結果を確認した" },
          { id: "consent", label: "輸血同意・実施の妥当性を確認した" },
        ];

  return (
    <main className="mx-auto w-full max-w-5xl px-4 py-6 sm:px-6 sm:py-8">
      {/* ── page heading (single h1) ── */}
      <header className="mb-6">
        <div className="flex flex-wrap items-center gap-2">
          <IconSlice className="h-6 w-6 text-foreground" aria-hidden />
          <h1 className="text-2xl font-bold tracking-tight text-foreground sm:text-3xl">
            手術記録 / 麻酔記録
          </h1>
          {statusBadge(status)}
        </div>
        <p className="mt-1 text-sm text-muted-foreground">
          WHO手術安全チェックリストを運用し、タイムアウトの2人確認・器械/ガーゼカウントの照合・麻薬/輸血の2人確認を経てサインアウトします。
        </p>
      </header>

      {/* ── 手術ヘッダ (patient + team context) ── */}
      <Card className="mb-6">
        <CardContent className="p-4 sm:p-5">
          <div className="flex flex-wrap items-start justify-between gap-3">
            <div className="flex items-center gap-3">
              <span className="flex h-11 w-11 items-center justify-center rounded-full bg-muted">
                <IconUser className="h-6 w-6 text-muted-foreground" aria-hidden />
              </span>
              <div>
                <div className="flex flex-wrap items-center gap-2">
                  <h2 className="text-lg font-semibold text-foreground">{C.name}</h2>
                  <Badge variant="outline" className="font-normal">
                    {C.kana}
                  </Badge>
                </div>
                <p className="text-sm text-muted-foreground">
                  {C.age}歳 ・ {C.sex}性 ・ ID {C.patientId} ・ {C.asa}
                </p>
              </div>
            </div>
            <div className="flex flex-col items-start gap-1.5 sm:items-end">
              <Badge variant="info" className="gap-1">
                <IconCalendarEvent className="h-3 w-3" aria-hidden />
                手術日 {C.date}
              </Badge>
              <span className="text-xs text-muted-foreground">
                入室 {C.inRoomAt} ／ 退室 {signedOut ? nowHm() : "—"}
              </span>
            </div>
          </div>

          {/* allergy line — never colour-only */}
          {C.allergies.length > 0 ? (
            <div className="mt-3" aria-live="polite">
              <Badge variant="destructive" className="gap-1">
                <IconAlertTriangle className="h-3 w-3" aria-hidden />
                アレルギー：{C.allergies.join("・")}
              </Badge>
            </div>
          ) : null}

          <Separator className="my-4" />

          <dl className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3">
            <HeaderFact icon={IconSlice} label="予定術式">
              {C.procedurePlanned}
              {C.side !== "該当なし" ? `（${C.side}）` : ""}
            </HeaderFact>
            <HeaderFact icon={IconStethoscope} label="執刀医 / 助手">
              {C.surgeon} ／ {C.assistant}
            </HeaderFact>
            <HeaderFact icon={IconActivityHeartbeat} label="麻酔科医">
              {C.anesthesiologist}
            </HeaderFact>
            <HeaderFact icon={IconUsers} label="器械出し看護師">
              {C.scrubNurse}
            </HeaderFact>
            <HeaderFact icon={IconUsers} label="外回り看護師">
              {C.circulatingNurse}
            </HeaderFact>
            <HeaderFact icon={IconDroplet} label="血液型">
              {C.bloodType}
            </HeaderFact>
          </dl>

          <Separator className="my-4" />

          <Stepper steps={steps} className="!p-0" />
        </CardContent>
      </Card>

      {/* ── persistent count-mismatch / retained-object block (assertive) ── */}
      {hasMismatch ? (
        <div className="mb-6">
          <SafetyBanner
            tone="destructive"
            title="カウント不一致 — 体内遺残のリスク"
            titleAs="h2"
            requireAck
            acknowledged={mismatchAck}
            onAcknowledge={() => setMismatchAck(true)}
            ackLabel="再カウント／X線確認を実施した"
            acknowledgedLabel="対応を確認済み"
          >
            <p>
              {mismatches.map((m) => `${m.row.label}（最終 ${m.row.final} / 予定 ${m.expected}）`).join("、")}
              が一致しません。サインアウトはブロックされています。再カウントまたはX線確認で遺残がないことを確認してください。
            </p>
          </SafetyBanner>
        </div>
      ) : null}

      {/* ── tabs ── */}
      <Tabs defaultValue="checklist">
        <TabsList className="flex w-full flex-wrap">
          <TabsTrigger value="checklist" className="gap-1.5">
            <IconChecklist className="h-4 w-4" aria-hidden />
            安全チェック
          </TabsTrigger>
          <TabsTrigger value="counts" className="gap-1.5">
            <IconClipboardCheck className="h-4 w-4" aria-hidden />
            カウント
            {hasMismatch ? (
              <Badge variant="destructive" className="ml-1">
                不一致
              </Badge>
            ) : null}
          </TabsTrigger>
          <TabsTrigger value="controlled" className="gap-1.5">
            <IconPill className="h-4 w-4" aria-hidden />
            麻薬・輸血
            {adminPending.length > 0 ? (
              <Badge variant="warning" className="ml-1">
                確認 {adminPending.length}
              </Badge>
            ) : null}
          </TabsTrigger>
          <TabsTrigger value="anesthesia" className="gap-1.5">
            <IconActivityHeartbeat className="h-4 w-4" aria-hidden />
            麻酔記録
          </TabsTrigger>
          <TabsTrigger value="note" className="gap-1.5">
            <IconReportMedical className="h-4 w-4" aria-hidden />
            手術記録
          </TabsTrigger>
        </TabsList>

        {/* ═══ 安全チェックリスト ═══ */}
        <TabsContent value="checklist" className="space-y-6 px-0">
          <ChecklistSection
            checked={checked}
            onToggle={toggleCheck}
            timeoutItemsDone={timeoutItemsDone}
            timeoutCoSign={timeoutCoSign}
            onOpenTimeoutCoSign={() => setTimeoutDialog(true)}
          />
        </TabsContent>

        {/* ═══ カウント ═══ */}
        <TabsContent value="counts" className="space-y-6 px-0">
          <CountSection
            countsWithEval={countsWithEval}
            allCounted={allCounted}
            hasMismatch={hasMismatch}
            countCoSign={countCoSign}
            onSetFinal={setFinal}
            onOpenCountCoSign={() => setCountDialog(true)}
            mismatchAck={mismatchAck}
            resolution={resolution}
            onResolution={setResolution}
          />
        </TabsContent>

        {/* ═══ 麻薬・輸血 (each needs 2人確認) ═══ */}
        <TabsContent value="controlled" className="space-y-6 px-0">
          <ControlledSection
            items={controlled}
            coSigns={adminCoSigns}
            onOpen={(a) => setAdminDialogFor(a)}
          />
        </TabsContent>

        {/* ═══ 麻酔記録 ═══ */}
        <TabsContent value="anesthesia" className="space-y-6 px-0">
          <AnesthesiaSection />
        </TabsContent>

        {/* ═══ 手術記録 (operative note, signed → append-only) ═══ */}
        <TabsContent value="note" className="space-y-6 px-0">
          <OperativeNoteSection
            body={noteBody}
            onBody={setNoteBody}
            signed={noteSigned}
            signedBy={noteSignedBy}
            signedAt={noteSignedAt}
            addenda={addenda}
            onSign={() => {
              setNoteSigned(true);
              setNoteSignedBy(C.surgeon);
              setNoteSignedAt(nowHm());
            }}
            onAddAddendum={(body) =>
              setAddenda((prev) => [
                ...prev,
                { id: `ad-${Date.now()}`, body, author: C.surgeon, at: nowHm() },
              ])
            }
          />
        </TabsContent>
      </Tabs>

      {/* ── サインアウト close bar ── */}
      <section aria-label="サインアウト" className="mt-8">
        <SignOutBar
          timeoutComplete={timeoutComplete}
          countsReconciled={countsReconciled}
          allAdminCoSigned={allAdminCoSigned}
          allCounted={allCounted}
          hasMismatch={hasMismatch}
          noteSigned={noteSigned}
          blocked={signoutBlocked}
          signedOut={signedOut}
          onSignOut={() => setSignedOut(true)}
        />
      </section>

      {/* ── co-sign composers ── */}
      <CoSignDialog
        open={timeoutDialog}
        onOpenChange={setTimeoutDialog}
        title="タイムアウト 2人確認（執刀前）"
        description="執刀前に、執刀医に加えて器械出し看護師が患者・術式・部位を独立に確認し、2人で確定します。"
        primaryId={C.surgeon}
        primaryRoleLabel="執刀医"
        signerLabel="確認看護師（ID・氏名）"
        signerPlaceholder="例：鈴木 花子 看護師"
        attestations={[
          { id: "patient", label: "患者・氏名・IDがリストバンドと一致することを確認した" },
          { id: "procedure", label: "術式・部位・左右が同意書・マーキングと一致することを確認した" },
          { id: "count", label: "器械・ガーゼ・針の開始時カウントが完了していることを確認した" },
        ]}
        confirmLabel="タイムアウトを2人で確定"
        onConfirm={(v) => {
          setTimeoutCoSign(v);
          setTimeoutDialog(false);
        }}
      />

      <CoSignDialog
        open={countDialog}
        onOpenChange={setCountDialog}
        title="最終カウント 2人確認"
        description="器械出し看護師と外回り看護師の2人で、最終カウントが開始時カウントと一致することを声出し確認します。"
        primaryId={C.scrubNurse}
        primaryRoleLabel="器械出し看護師"
        signerLabel="外回り看護師（ID・氏名）"
        signerPlaceholder="例：田中 美咲 看護師"
        attestations={[
          { id: "gauze", label: "ガーゼ・器械・針の最終カウントを2人で実施した" },
          { id: "match", label: "最終カウントが開始時カウント＋追加分と一致することを確認した" },
        ]}
        confirmLabel="カウントを2人で確定"
        onConfirm={(v) => {
          setCountCoSign(v);
          setCountDialog(false);
        }}
      />

      <CoSignDialog
        open={adminDialogFor !== null}
        onOpenChange={(o) => {
          if (!o) setAdminDialogFor(null);
        }}
        title={
          adminDialogFor
            ? `${adminDialogFor.category} 2人確認 — ${adminDialogFor.name}`
            : "2人確認"
        }
        description={
          adminDialogFor
            ? `${adminDialogFor.detail}（${adminDialogFor.time}・実施 ${adminDialogFor.primary}）について、2人目の担当者が独立に確認します。`
            : ""
        }
        primaryId={adminDialogFor?.primary ?? ""}
        primaryRoleLabel="実施者"
        signerLabel="確認者（医師・看護師 ID・氏名）"
        signerPlaceholder="例：田中 美咲 看護師"
        attestations={adminDialogFor ? adminAttestations(adminDialogFor) : []}
        requireReason={false}
        reasonPlaceholder="特記事項があれば記載"
        confirmLabel="2人確認を確定"
        onConfirm={(v) => {
          if (adminDialogFor) {
            setAdminCoSigns((m) => ({ ...m, [adminDialogFor.id]: v }));
            setAdminDialogFor(null);
          }
        }}
      />
    </main>
  );
}

/* ═══════════════════════════════════════════════════════════════════
   SECTION: 安全チェックリスト
   ═══════════════════════════════════════════════════════════════════ */

function ChecklistSection({
  checked,
  onToggle,
  timeoutItemsDone,
  timeoutCoSign,
  onOpenTimeoutCoSign,
}: {
  checked: Set<string>;
  onToggle: (id: string) => void;
  timeoutItemsDone: boolean;
  timeoutCoSign?: CoSignValue;
  onOpenTimeoutCoSign: () => void;
}) {
  const phases: ChecklistPhase[] = ["signin", "timeout", "signout"];
  return (
    <div className="space-y-5">
      {phases.map((phase) => {
        const items = checklistItems.filter((i) => i.phase === phase);
        const done = items.filter((i) => checked.has(i.id)).length;
        const allDone = done === items.length;
        const isTimeout = phase === "timeout";
        const meta = PHASE_META[phase];
        return (
          <Card key={phase}>
            <CardHeader className="gap-1 p-4 sm:p-5">
              <div className="flex flex-wrap items-center justify-between gap-2">
                <CardTitle as="h2" className="text-lg">
                  {meta.label}
                  <span className="ml-2 text-sm font-normal text-muted-foreground">
                    （{meta.when}）
                  </span>
                </CardTitle>
                <Badge variant={allDone ? "success" : "secondary"} className="gap-1">
                  {allDone ? <IconCircleCheck className="h-3 w-3" aria-hidden /> : null}
                  {done}/{items.length}
                </Badge>
              </div>
            </CardHeader>
            <CardContent className="space-y-2 p-4 pt-0 sm:p-5 sm:pt-0">
              <ul className="space-y-2">
                {items.map((item) => {
                  const isChecked = checked.has(item.id);
                  return (
                    <li
                      key={item.id}
                      className="flex items-start gap-3 rounded-md border border-border bg-card p-3"
                    >
                      <Checkbox
                        checked={isChecked}
                        onCheckedChange={() => onToggle(item.id)}
                        className="mt-0.5"
                        label={
                          <span className={isChecked ? "text-muted-foreground" : "text-foreground"}>
                            {item.label}
                          </span>
                        }
                        description={item.hint}
                      />
                    </li>
                  );
                })}
              </ul>

              {/* タイムアウト two-person sign-off */}
              {isTimeout ? (
                <div className="mt-3 rounded-lg border border-info-border bg-info-subtle/50 p-3">
                  <div className="flex flex-wrap items-center justify-between gap-2">
                    <div className="flex items-center gap-2">
                      <IconUsers className="h-4 w-4 text-info" aria-hidden />
                      <span className="text-sm font-medium text-foreground">
                        執刀前タイムアウトの2人確認
                      </span>
                      <CoSignBadge value={timeoutCoSign} />
                    </div>
                    {timeoutCoSign ? null : (
                      <Button
                        size="sm"
                        variant="info"
                        disabled={!timeoutItemsDone}
                        onClick={onOpenTimeoutCoSign}
                      >
                        <IconUsers className="h-4 w-4" aria-hidden />
                        2人で確定
                      </Button>
                    )}
                  </div>
                  {timeoutCoSign ? (
                    <div className="mt-2">
                      <CoSignAudit primaryId={surgeryCase.surgeon} value={timeoutCoSign} />
                    </div>
                  ) : (
                    <p className="mt-1.5 text-xs text-muted-foreground">
                      {timeoutItemsDone
                        ? "全項目を確認しました。執刀医と看護師の2人で確定すると執刀できます。"
                        : "上記の全項目を確認してから2人確認に進みます。"}
                    </p>
                  )}
                </div>
              ) : null}
            </CardContent>
          </Card>
        );
      })}
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════
   SECTION: 器械・ガーゼ・針 カウント
   ═══════════════════════════════════════════════════════════════════ */

interface CountEval {
  row: CountRow;
  expected: number;
  counted: boolean;
  matches: boolean;
}

function CountSection({
  countsWithEval,
  allCounted,
  hasMismatch,
  countCoSign,
  onSetFinal,
  onOpenCountCoSign,
  mismatchAck,
  resolution,
  onResolution,
}: {
  countsWithEval: CountEval[];
  allCounted: boolean;
  hasMismatch: boolean;
  countCoSign?: CoSignValue;
  onSetFinal: (id: string, value: number | null) => void;
  onOpenCountCoSign: () => void;
  mismatchAck: boolean;
  resolution: string;
  onResolution: (v: string) => void;
}) {
  return (
    <div className="space-y-4">
      <Alert variant={hasMismatch ? "destructive" : allCounted ? "success" : "info"}>
        {hasMismatch ? (
          <IconAlertTriangle className="h-4 w-4" aria-hidden />
        ) : allCounted ? (
          <IconCircleCheck className="h-4 w-4" aria-hidden />
        ) : (
          <IconClipboardCheck className="h-4 w-4" aria-hidden />
        )}
        <AlertTitle as="h2" className="text-sm">
          {hasMismatch
            ? "最終カウント不一致 — 体内遺残のリスク"
            : allCounted
              ? "最終カウント一致"
              : "最終カウント未完了"}
        </AlertTitle>
        <AlertDescription>
          {hasMismatch
            ? "一致しない品目があります。再カウント／X線確認で遺残がないことを確認するまでサインアウトできません。"
            : allCounted
              ? "開始時＋追加分と最終カウントが全品目で一致しました。2人確認で確定します。"
              : "閉創前／退室時に器械・ガーゼ・針を2人で数え、開始時カウントと照合します。"}
        </AlertDescription>
      </Alert>

      <Card>
        <CardHeader className="p-4 sm:p-5">
          <CardTitle as="h2" className="text-lg">
            カウント照合表
          </CardTitle>
          <CardDescription>
            最終カウントが「開始時＋追加」と一致する必要があります。一致しない場合は体内遺残のリスクとして警告します。
          </CardDescription>
        </CardHeader>
        <CardContent className="p-4 pt-0 sm:p-5 sm:pt-0">
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>品目</TableHead>
                <TableHead className="text-right">開始時</TableHead>
                <TableHead className="text-right">追加</TableHead>
                <TableHead className="text-right">予定最終</TableHead>
                <TableHead className="text-right">最終カウント</TableHead>
                <TableHead className="text-right">照合</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {countsWithEval.map(({ row, expected, counted, matches }) => (
                <TableRow key={row.id}>
                  <TableCell className="font-medium">{row.label}</TableCell>
                  <TableCell className="text-right tabular-nums">{row.initial}</TableCell>
                  <TableCell className="text-right tabular-nums text-muted-foreground">
                    +{row.added}
                  </TableCell>
                  <TableCell className="text-right tabular-nums font-medium">{expected}</TableCell>
                  <TableCell className="text-right">
                    <label className="sr-only" htmlFor={`final-${row.id}`}>
                      {row.label} の最終カウント
                    </label>
                    <Input
                      id={`final-${row.id}`}
                      type="number"
                      inputMode="numeric"
                      min={0}
                      value={row.final ?? ""}
                      onChange={(e) =>
                        onSetFinal(
                          row.id,
                          e.target.value === "" ? null : Number(e.target.value),
                        )
                      }
                      className="ml-auto w-20 text-right tabular-nums"
                      aria-invalid={counted && !matches ? true : undefined}
                      placeholder="—"
                    />
                  </TableCell>
                  <TableCell className="text-right">
                    {!counted ? (
                      <Badge variant="secondary">未</Badge>
                    ) : matches ? (
                      <Badge variant="success" className="gap-1">
                        <IconCircleCheck className="h-3 w-3" aria-hidden />
                        一致
                      </Badge>
                    ) : (
                      <Badge variant="destructive" className="gap-1">
                        <IconAlertTriangle className="h-3 w-3" aria-hidden />
                        不一致
                      </Badge>
                    )}
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
            <TableFooter>
              <TableRow>
                <TableCell colSpan={5} className="text-right text-xs text-muted-foreground">
                  全{countsWithEval.length}品目 ・ 一致{" "}
                  {countsWithEval.filter((c) => c.counted && c.matches).length} ／ 不一致{" "}
                  {countsWithEval.filter((c) => c.counted && !c.matches).length}
                </TableCell>
                <TableCell className="text-right">
                  {countCoSign ? <CoSignBadge value={countCoSign} /> : null}
                </TableCell>
              </TableRow>
            </TableFooter>
          </Table>

          {/* mismatch resolution method */}
          {hasMismatch ? (
            <div className="mt-4 space-y-3 rounded-lg border border-destructive-border bg-destructive-subtle/40 p-3">
              <p className="text-sm font-medium text-destructive-subtle-foreground">
                <IconAlertTriangle className="mr-1 inline h-4 w-4" aria-hidden />
                不一致への対応（必須）
              </p>
              <div className="max-w-xs">
                <Select
                  label="対応方法"
                  value={resolution}
                  onChange={(e) => onResolution(e.target.value)}
                >
                  <option value="">選択してください</option>
                  <option value="recount">再カウントで一致を確認</option>
                  <option value="xray">術中X線で遺残なしを確認</option>
                  <option value="found">遺残物を発見・除去</option>
                </Select>
              </div>
              {mismatchAck ? (
                <p className="text-xs font-medium text-success-strong">
                  <IconCircleCheck className="mr-1 inline h-3.5 w-3.5" aria-hidden />
                  対応を確認済み。最終カウントを修正のうえ2人確認で確定してください。
                </p>
              ) : (
                <p className="text-xs text-destructive-subtle-foreground">
                  上部の安全バナーで対応を確認してください。サインアウトはブロックされています。
                </p>
              )}
            </div>
          ) : null}

          {/* 2人カウント co-sign */}
          <div className="mt-4 flex flex-wrap items-center justify-between gap-2">
            <div className="flex items-center gap-2">
              <IconUsers className="h-4 w-4 text-muted-foreground" aria-hidden />
              <span className="text-sm font-medium text-foreground">2人カウントの確定</span>
              <CoSignBadge value={countCoSign} />
            </div>
            {countCoSign ? (
              <CoSignAudit primaryId={surgeryCase.scrubNurse} value={countCoSign} />
            ) : (
              <Button
                size="sm"
                variant="success"
                disabled={!allCounted || (hasMismatch && !mismatchAck)}
                onClick={onOpenCountCoSign}
              >
                <IconUsers className="h-4 w-4" aria-hidden />
                2人で確定
              </Button>
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════
   SECTION: 麻薬・輸血 (each needs 2人確認)
   ═══════════════════════════════════════════════════════════════════ */

function ControlledSection({
  items,
  coSigns,
  onOpen,
}: {
  items: ControlledAdmin[];
  coSigns: Record<string, CoSignValue>;
  onOpen: (a: ControlledAdmin) => void;
}) {
  return (
    <div className="space-y-4">
      <Alert variant="warning">
        <IconAlertTriangle className="h-4 w-4" aria-hidden />
        <AlertTitle as="h2" className="text-sm">
          麻薬・輸血は実施ごとに2人確認が必要です
        </AlertTitle>
        <AlertDescription>
          実施者に加えて2人目の担当者（実施者と別人）が独立に確認し、co-sign します。
        </AlertDescription>
      </Alert>

      <ul className="space-y-3">
        {items.map((a) => {
          const signed = coSigns[a.id];
          return (
            <li key={a.id}>
              <Card className={signed ? "border-success-border/60" : "border-warning-border/60"}>
                <CardContent className="space-y-3 p-4 sm:p-5">
                  <div className="flex flex-wrap items-start justify-between gap-2">
                    <div className="flex items-start gap-2">
                      <span className="mt-0.5 flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-muted">
                        {a.category === "麻薬" ? (
                          <IconPill className="h-4 w-4 text-muted-foreground" aria-hidden />
                        ) : (
                          <IconDroplet className="h-4 w-4 text-muted-foreground" aria-hidden />
                        )}
                      </span>
                      <div>
                        <div className="flex flex-wrap items-center gap-2">
                          <h3 className="text-base font-semibold text-foreground">{a.name}</h3>
                          <Badge variant={a.category === "麻薬" ? "destructive" : "info"}>
                            {a.category}
                          </Badge>
                        </div>
                        <p className="text-sm text-muted-foreground">{a.detail}</p>
                        <p className="text-xs text-muted-foreground">
                          <IconClockHour4 className="mr-1 inline h-3 w-3" aria-hidden />
                          {a.time} ・ 実施 {a.primary}
                        </p>
                      </div>
                    </div>
                    <CoSignBadge value={signed} />
                  </div>

                  {signed ? (
                    <div className="rounded-md border border-success-border/50 bg-success-subtle/40 px-3 py-2">
                      <CoSignAudit primaryId={a.primary} value={signed} />
                    </div>
                  ) : (
                    <div className="flex justify-end">
                      <Button size="sm" variant="warning" onClick={() => onOpen(a)}>
                        <IconUsers className="h-4 w-4" aria-hidden />
                        2人確認を行う
                      </Button>
                    </div>
                  )}
                </CardContent>
              </Card>
            </li>
          );
        })}
      </ul>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════
   SECTION: 麻酔記録 (anesthesia)
   ═══════════════════════════════════════════════════════════════════ */

function AnesthesiaSection() {
  const labels = vitalTrend.map((v) => v.time);
  const totalIn = fluidLog
    .filter((f) => f.category === "輸液")
    .reduce((s, f) => s + f.ml, 0);
  const loss = fluidLog.find((f) => f.category === "出血")?.ml ?? 0;
  const urine = fluidLog.find((f) => f.category === "尿量")?.ml ?? 0;

  return (
    <div className="space-y-5">
      {/* intraop KPIs */}
      <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
        <Statistic label="輸液 合計" value={`${totalIn.toLocaleString()} mL`} />
        <Statistic label="出血量" value={`${loss.toLocaleString()} mL`} tone="negative" />
        <Statistic label="尿量" value={`${urine.toLocaleString()} mL`} />
        <Statistic label="水分バランス" value={`+${(totalIn - loss - urine).toLocaleString()} mL`} />
      </div>

      {/* intraop trend */}
      <Card>
        <CardHeader className="p-4 sm:p-5">
          <CardTitle as="h2" className="text-lg">
            術中バイタル推移
          </CardTitle>
          <CardDescription>09:15〜11:00 ・ HR / 平均血圧(MAP) / SpO2</CardDescription>
        </CardHeader>
        <CardContent className="p-4 pt-0 sm:p-5 sm:pt-0">
          <LineChart
            showLegend
            showGrid
            showLabels
            series={[
              {
                label: "HR (bpm)",
                color: "info",
                data: vitalTrend.map((v, i) => ({ label: labels[i], value: v.hr })),
              },
              {
                label: "MAP (mmHg)",
                color: "warning",
                data: vitalTrend.map((v, i) => ({ label: labels[i], value: v.map })),
              },
              {
                label: "SpO2 (%)",
                color: "success",
                data: vitalTrend.map((v, i) => ({ label: labels[i], value: v.spo2 })),
              },
            ]}
          />
          <p className="mt-2 text-xs text-muted-foreground">
            10:30〜10:45 に MAP 低下・HR 上昇（出血に伴う）。輸血・輸液で 11:00 に回復。
          </p>
        </CardContent>
      </Card>

      {/* flowsheet table with ReferenceValue flags */}
      <Card>
        <CardHeader className="p-4 sm:p-5">
          <CardTitle as="h2" className="text-lg">
            麻酔記録フローシート
          </CardTitle>
          <CardDescription>各時刻のバイタルを術中基準値と照合（基準外は色＋記号＋読み上げ）</CardDescription>
        </CardHeader>
        <CardContent className="p-4 pt-0 sm:p-5 sm:pt-0">
          <Table striped>
            <TableHeader>
              <TableRow>
                <TableHead>時刻</TableHead>
                <TableHead className="text-right">HR</TableHead>
                <TableHead className="text-right">MAP</TableHead>
                <TableHead className="text-right">SpO2</TableHead>
                <TableHead className="text-right">EtCO2</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {vitalTrend.map((v) => (
                <TableRow key={v.time}>
                  <TableCell className="font-medium tabular-nums">{v.time}</TableCell>
                  <TableCell className="text-right">
                    <ReferenceValue size="inline" value={v.hr} range={VITAL_RANGES.hr} unit="bpm" />
                  </TableCell>
                  <TableCell className="text-right">
                    <ReferenceValue size="inline" value={v.map} range={VITAL_RANGES.map} unit="mmHg" />
                  </TableCell>
                  <TableCell className="text-right">
                    <ReferenceValue size="inline" value={v.spo2} range={VITAL_RANGES.spo2} unit="%" />
                  </TableCell>
                  <TableCell className="text-right">
                    <ReferenceValue size="inline" value={v.etco2} range={VITAL_RANGES.etco2} unit="mmHg" />
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </CardContent>
      </Card>

      {/* 輸液・出血量 + events timeline */}
      <div className="grid gap-5 lg:grid-cols-2">
        <Card>
          <CardHeader className="p-4 sm:p-5">
            <CardTitle as="h2" className="text-lg">
              輸液・出血・尿量
            </CardTitle>
          </CardHeader>
          <CardContent className="p-4 pt-0 sm:p-5 sm:pt-0">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>項目</TableHead>
                  <TableHead>区分</TableHead>
                  <TableHead className="text-right">量</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {fluidLog.map((f) => (
                  <TableRow key={f.id}>
                    <TableCell className="font-medium">{f.label}</TableCell>
                    <TableCell>
                      <Badge variant="outline" className="font-normal">
                        {f.category}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-right tabular-nums">{f.amount}</TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="p-4 sm:p-5">
            <CardTitle as="h2" className="text-lg">
              麻酔イベント
            </CardTitle>
          </CardHeader>
          <CardContent className="p-4 pt-0 sm:p-5 sm:pt-0">
            <Timeline>
              {[
                { t: "09:15", title: "全身麻酔導入・気管挿管", variant: "info" as const },
                { t: "09:38", title: "執刀開始（タイムアウト後）", variant: "default" as const },
                { t: "10:30", title: "出血・一時的に低血圧", variant: "warning" as const },
                { t: "10:55", title: "赤血球濃厚液 1単位 輸血", variant: "destructive" as const },
                { t: "11:00", title: "循環安定・閉創開始", variant: "success" as const },
              ].map((e, i, arr) => (
                <TimelineItem key={e.t} variant={e.variant} connector={i < arr.length - 1}>
                  <TimelineTitle>{e.title}</TimelineTitle>
                  <TimelineTime dateTime={e.t}>{e.t}</TimelineTime>
                </TimelineItem>
              ))}
            </Timeline>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════════════
   SECTION: 手術記録 (operative note — signed → append-only)
   ═══════════════════════════════════════════════════════════════════ */

function OperativeNoteSection({
  body,
  onBody,
  signed,
  signedBy,
  signedAt,
  addenda,
  onSign,
  onAddAddendum,
}: {
  body: string;
  onBody: (v: string) => void;
  signed: boolean;
  signedBy: string | null;
  signedAt: string | null;
  addenda: { id: string; body: string; author: string; at: string }[];
  onSign: () => void;
  onAddAddendum: (body: string) => void;
}) {
  const [addOpen, setAddOpen] = React.useState(false);
  const [addText, setAddText] = React.useState("");
  const [confirmOpen, setConfirmOpen] = React.useState(false);

  const submitAddendum = () => {
    if (!addText.trim()) return;
    onAddAddendum(addText.trim());
    setAddText("");
    setAddOpen(false);
  };

  return (
    <Card className={signed ? "border-success-border/60" : undefined}>
      <CardHeader className="p-4 sm:p-5">
        <div className="flex flex-wrap items-center justify-between gap-2">
          <CardTitle as="h2" className="text-lg">
            手術記録（所見・手技・経過）
          </CardTitle>
          {signed ? (
            <Badge variant="success" className="gap-1">
              <IconLock className="h-3 w-3" aria-hidden />
              署名済 ・ 記録確定
            </Badge>
          ) : (
            <Badge variant="warning" className="gap-1">
              <IconLockOpen className="h-3 w-3" aria-hidden />
              下書き ・ 未署名
            </Badge>
          )}
        </div>
        <CardDescription>
          執刀医が記載し、署名により確定します。署名後は編集できず、追記（addendum）のみ可能です。
        </CardDescription>
      </CardHeader>

      <CardContent className="space-y-4 p-4 pt-0 sm:p-5 sm:pt-0">
        {signed ? (
          <div className="whitespace-pre-wrap break-words rounded-md border border-border bg-muted/30 p-3 text-sm text-foreground">
            {body}
          </div>
        ) : (
          <FormField>
            <FormLabel>術中所見・手技・経過</FormLabel>
            <FormControl>
              <Textarea
                value={body}
                onChange={(e) => onBody(e.target.value)}
                rows={8}
                placeholder="体位・到達法・所見・手技・出血・合併症・閉創を記載"
              />
            </FormControl>
          </FormField>
        )}

        {signed ? (
          <div className="rounded-md border border-success-border/50 bg-success-subtle/40 px-3 py-2 text-xs text-success-subtle-foreground">
            <span className="inline-flex items-center gap-1 font-semibold">
              <IconSignature className="h-3.5 w-3.5" aria-hidden />
              {signedBy} が署名
            </span>
            <span className="ml-1">（{signedAt}）</span>
            <span className="ml-1">この記録は確定済みのため編集できません。修正は追記で行います。</span>
          </div>
        ) : null}

        {/* addendum chain */}
        {addenda.length > 0 ? (
          <ul className="space-y-2 border-l-2 border-info-border/60 pl-3">
            {addenda.map((ad, i) => (
              <li key={ad.id} className="text-sm">
                <div className="flex flex-wrap items-center gap-2 text-xs text-muted-foreground">
                  <Badge variant="info" className="gap-1">
                    <IconCornerDownRight className="h-3 w-3" aria-hidden />
                    追記 {i + 1}
                  </Badge>
                  <span>
                    {ad.at} ・ {ad.author}
                  </span>
                </div>
                <p className="mt-1 whitespace-pre-wrap break-words text-foreground">{ad.body}</p>
              </li>
            ))}
          </ul>
        ) : null}
      </CardContent>

      <CardFooter className="flex-wrap gap-2 p-4 pt-0 sm:p-5 sm:pt-0">
        {signed ? (
          <Dialog open={addOpen} onOpenChange={setAddOpen}>
            <Button variant="outline" size="sm" onClick={() => setAddOpen(true)}>
              <IconPlus className="h-4 w-4" aria-hidden />
              追記を追加
            </Button>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>追記 (Addendum)</DialogTitle>
                <DialogDescription>
                  確定済みの記録は変更できません。追記は独自のタイムスタンプ・記録者として記録の末尾に追加されます。
                </DialogDescription>
              </DialogHeader>
              <FormField>
                <FormLabel>追記内容</FormLabel>
                <FormControl>
                  <Textarea
                    value={addText}
                    onChange={(e) => setAddText(e.target.value)}
                    rows={4}
                    placeholder="経過の補足・修正内容を記載"
                  />
                </FormControl>
              </FormField>
              <DialogFooter>
                <Button variant="outline" onClick={() => setAddOpen(false)}>
                  キャンセル
                </Button>
                <Button onClick={submitAddendum} disabled={!addText.trim()}>
                  <IconCornerDownRight className="h-4 w-4" aria-hidden />
                  追記を保存
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>
        ) : (
          <>
            <Badge variant="warning" className="gap-1">
              <IconAlertTriangle className="h-3 w-3" aria-hidden />
              署名すると編集不可になります
            </Badge>
            <Dialog open={confirmOpen} onOpenChange={setConfirmOpen}>
              <Button
                variant="success"
                size="sm"
                className="ml-auto"
                disabled={!body.trim()}
                onClick={() => setConfirmOpen(true)}
              >
                <IconSignature className="h-4 w-4" aria-hidden />
                署名して確定
              </Button>
              <DialogContent>
                <DialogHeader>
                  <DialogTitle>手術記録の署名</DialogTitle>
                  <DialogDescription>
                    {surgeryCase.surgeon} として署名し、記録を確定します。確定後は編集できず追記のみ可能です。
                  </DialogDescription>
                </DialogHeader>
                <DialogFooter>
                  <Button variant="outline" onClick={() => setConfirmOpen(false)}>
                    戻る
                  </Button>
                  <Button
                    variant="success"
                    onClick={() => {
                      onSign();
                      setConfirmOpen(false);
                    }}
                  >
                    <IconSignature className="h-4 w-4" aria-hidden />
                    署名して確定
                  </Button>
                </DialogFooter>
              </DialogContent>
            </Dialog>
          </>
        )}
      </CardFooter>
    </Card>
  );
}

/* ═══════════════════════════════════════════════════════════════════
   サインアウト close bar
   ═══════════════════════════════════════════════════════════════════ */

function GateRow({ ok, label }: { ok: boolean; label: string }) {
  return (
    <li className="flex items-center gap-2 text-sm">
      {ok ? (
        <IconCircleCheck className="h-4 w-4 shrink-0 text-success-strong" aria-hidden />
      ) : (
        <IconX className="h-4 w-4 shrink-0 text-destructive" aria-hidden />
      )}
      <span className={ok ? "text-foreground" : "text-muted-foreground"}>{label}</span>
      <span className="sr-only">{ok ? "（完了）" : "（未完了）"}</span>
    </li>
  );
}

function SignOutBar({
  timeoutComplete,
  countsReconciled,
  allAdminCoSigned,
  allCounted,
  hasMismatch,
  noteSigned,
  blocked,
  signedOut,
  onSignOut,
}: {
  timeoutComplete: boolean;
  countsReconciled: boolean;
  allAdminCoSigned: boolean;
  allCounted: boolean;
  hasMismatch: boolean;
  noteSigned: boolean;
  blocked: boolean;
  signedOut: boolean;
  onSignOut: () => void;
}) {
  if (signedOut) {
    return (
      <Alert variant="success">
        <IconCircleCheck className="h-4 w-4" aria-hidden />
        <AlertTitle as="h2" className="text-sm">
          サインアウト完了 ・ 退室済
        </AlertTitle>
        <AlertDescription>
          安全チェック・カウント照合・麻薬/輸血の2人確認がすべて完了し、退室を記録しました。
        </AlertDescription>
      </Alert>
    );
  }

  return (
    <Card className={blocked ? "border-destructive-border/60" : "border-success-border/60"}>
      <CardHeader className="p-4 sm:p-5">
        <CardTitle as="h2" className="text-lg">
          サインアウト（退室前）
        </CardTitle>
        <CardDescription>
          下記の安全ゲートがすべて完了するまで退室を確定できません。
        </CardDescription>
      </CardHeader>
      <CardContent className="p-4 pt-0 sm:p-5 sm:pt-0">
        {/* announce blocking reasons assertively */}
        {hasMismatch ? (
          <div aria-live="assertive" className="sr-only">
            カウント不一致のためサインアウトがブロックされています。
          </div>
        ) : null}
        <ul className="space-y-1.5">
          <GateRow ok={timeoutComplete} label="タイムアウトの2人確認が完了" />
          <GateRow
            ok={allCounted && !hasMismatch}
            label={
              hasMismatch
                ? "最終カウントが一致（不一致 — 体内遺残のリスク）"
                : "最終カウントが一致"
            }
          />
          <GateRow ok={countsReconciled} label="2人カウントで確定（不一致時は対応を確認）" />
          <GateRow ok={allAdminCoSigned} label="麻薬・輸血の2人確認がすべて完了" />
          <GateRow ok={noteSigned} label="手術記録に署名（任意 — 退室後でも可）" />
        </ul>
      </CardContent>
      <CardFooter className="flex-wrap items-center gap-2 p-4 pt-0 sm:p-5 sm:pt-0">
        {blocked ? (
          <Badge variant="warning" className="gap-1">
            <IconLock className="h-3 w-3" aria-hidden />
            必須ゲート未完了
          </Badge>
        ) : (
          <Badge variant="success" className="gap-1">
            <IconLockOpen className="h-3 w-3" aria-hidden />
            退室可
          </Badge>
        )}
        <Button
          variant={blocked ? "outline" : "success"}
          className="ml-auto"
          disabled={blocked}
          onClick={onSignOut}
        >
          <IconCircleCheck className="h-4 w-4" aria-hidden />
          サインアウト・退室を確定
        </Button>
      </CardFooter>
    </Card>
  );
}
